WITH payload AS (
  SELECT $RISQQ81${"questions":[{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.7","internal_question_no":"08B.007","question_sort_key":8200700.222,"question_text":"Are the stresses, stability information and any limitations included in the cargo plan understood by the cargo watch officers and are conditions being monitored and maintained within design limits throughout cargo operations?","guide_to_inspection":"Inspectors should make sure that regular monitoring of stress and stability have been taking place throughout cargo operations\nand verify if the vessel’s condition has been maintained within design limits.\nThe officer in charge should closely monitor the ship’s condition during cargo operations. If a significant deviation from the\nagreed loading/unloading plan is detected, all cargo and ballast operations must STOP.\nThe officer in charge should ensure that;\n> The cargo operations and intended ballast/de-ballast procedure are synchronised.\n> Draught surveys are conducted at appropriate steps of the loading/discharge plan to verify the ship’s condition.\n> The draught readings, usually taken at amidships and the fore and aft perpendiculars, should be in good agreement with\nvalues calculated in the loading/discharging plan.\n> Ballast tanks are sounded to verify their contents and rate of ballasting/de-ballasting.\n> The cargo load agrees with the figures provided by the terminal.\n> The SWSF, SWBM and, where appropriate, hold cargo weight versus draught calculations are performed at intermediate\nstages of the cargo operation. These results should be logged.\n> Any revised loading/unloading plan should be signed by a terminal representative and by the Master or Chief Officer.\n> The Master and Chief Officer should be aware of the worst-case damage condition for the existing cargo on board.\n> Cargo trimming is a mandatory requirement for grain cargoes. The loading and unloading plan should indicate any\nallowance for cargo trimming.\n(Guidance and Information on Bulk Cargo Loading and Discharging to\nReduce the Likelihood of Over-stressing the Hull Structure, 2018)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":122,"source_page_end":122,"raw_source_text":"Are the stresses, stability information and any limitations included in the cargo plan understood\nby the cargo watch officers and are conditions being monitored and maintained within design limits\nthroughout cargo operations? (V)\nGuide to Inspection\nInspectors should make sure that regular monitoring of stress and stability have been taking place throughout cargo operations\nand verify if the vessel’s condition has been maintained within design limits.\nThe officer in charge should closely monitor the ship’s condition during cargo operations. If a significant deviation from the\nagreed loading/unloading plan is detected, all cargo and ballast operations must STOP.\nThe officer in charge should ensure that;\n> The cargo operations and intended ballast/de-ballast procedure are synchronised.\n> Draught surveys are conducted at appropriate steps of the loading/discharge plan to verify the ship’s condition.\n> The draught readings, usually taken at amidships and the fore and aft perpendiculars, should be in good agreement with\nvalues calculated in the loading/discharging plan.\n> Ballast tanks are sounded to verify their contents and rate of ballasting/de-ballasting.\n> The cargo load agrees with the figures provided by the terminal.\n> The SWSF, SWBM and, where appropriate, hold cargo weight versus draught calculations are performed at intermediate\nstages of the cargo operation. These results should be logged.\n> Any revised loading/unloading plan should be signed by a terminal representative and by the Master or Chief Officer.\n> The Master and Chief Officer should be aware of the worst-case damage condition for the existing cargo on board.\n> Cargo trimming is a mandatory requirement for grain cargoes. The loading and unloading plan should indicate any\nallowance for cargo trimming.\n(Guidance and Information on Bulk Cargo Loading and Discharging to\nReduce the Likelihood of Over-stressing the Hull Structure, 2018)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.8","internal_question_no":"08B.008","question_sort_key":8200800.223,"question_text":"Are there procedures in place for loading, ballasting and de-ballasting of the ballast holds?","guide_to_inspection":"When cargo is to be carried in ballast hold:\n> Proper steps should be taken to ensure that ballast water cannot be admitted to the hold by accident.\n> Blanks or cover plates which were fitted to the bilge, to the CO2 smothering lines and to the hatch coaming drains must be\nremoved so that these systems can operate whilst cargo is being carried.\nBefore ballasting of ballast hold:\n> It is vital to remove any blanks or cover plates which have been fitted to ballast suctions within the hold.\n> The bilge suctions should be sealed to prevent ballast from leaking through the bilge system.\n> The CO injection and the coaming drains must be sealed.\n2\n> Cargo residue and rubbish must be removed from the hold, as they could block the ballast suction.\nDeballasting:\n> Hatch cover ventilations must be open.\n(Bulk Carrier Practice, Isbester, 2013)\nHold vents must be open when ballasting and/or de-ballasting the designated ballast hold.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":122,"source_page_end":122,"raw_source_text":"Are there procedures in place for loading, ballasting and de-ballasting of the ballast holds? (V)\nGuide to Inspection\nWhen cargo is to be carried in ballast hold:\n> Proper steps should be taken to ensure that ballast water cannot be admitted to the hold by accident.\n> Blanks or cover plates which were fitted to the bilge, to the CO2 smothering lines and to the hatch coaming drains must be\nremoved so that these systems can operate whilst cargo is being carried.\nBefore ballasting of ballast hold:\n> It is vital to remove any blanks or cover plates which have been fitted to ballast suctions within the hold.\n> The bilge suctions should be sealed to prevent ballast from leaking through the bilge system.\n> The CO injection and the coaming drains must be sealed.\n2\n> Cargo residue and rubbish must be removed from the hold, as they could block the ballast suction.\nDeballasting:\n> Hatch cover ventilations must be open.\n(Bulk Carrier Practice, Isbester, 2013)\nHold vents must be open when ballasting and/or de-ballasting the designated ballast hold.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.9","internal_question_no":"08B.009","question_sort_key":8200900.224,"question_text":"Are there guidelines and procedures for hold cleaning in place","guide_to_inspection":"Record the list of hold cleaning equipment available on board in comments.\nBulk cargoes include a very wide range of commodities. The level of cleanliness required before loading and additional\npreparation will depend upon the type of cargo to be loaded. The vessel’s manager shall provide comprehensive hold cleaning\nguidelines, procedures, hold cleaning matrix for change of cargo and hold cleaning inspection checklist.\nCargo hold cleaning plans shall consist of the following steps, where applicable:\n1. Removal of dunnage, lashing material and/or cargo residues\n2. Holds swept down\n3. Holds swept down a second time (double swept)\n4. Cargo residues that have set hard removed\n5. Cleaning chemicals applied to hold surfaces and allowed to penetrate/react with stains prior to being washed off\n6. Holds washed down with sea water\n7. Holds washed down with detergents mixed in fresh water\n8. Holds rinsed with fresh water to remove all traces of chlorides and detergents\n9. Bilge wells and plates/strainers cleaned\n10. Holds air dried\n11. Loose paint flakes, loose rust scale and paint blisters removed\n12. Paintwork touched-up\n13. Barrier coat applied\nSome vessels are equipped with fixed cargo hold washing machines, however, these vessels are in a minority and most vessels\ncarrying solid bulk cargoes will need to manually wash the cargo holds. Where fixed washing machines are used, manual\ncleaning of shadow sectors within the holds may still be required. (Cargo Hold Cleaning, 2017)\nDuring the operation, the Master or Chief Officer should undertake inspections to ensure the cleaning is being carried out\ncorrectly using of the correct material and equipment. Inspections should be conducted at least once during each day by the\nMaster or Chief Officer accompanied by the Bosun, to establish how the operation is progressing.\nThe cargo hold cleaning checklist should be incorporated in the operator’s hold cleaning procedure.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":123,"source_page_end":123,"raw_source_text":"Are there guidelines and procedures for hold cleaning in place (V)\nGuide to Inspection\nRecord the list of hold cleaning equipment available on board in comments.\nBulk cargoes include a very wide range of commodities. The level of cleanliness required before loading and additional\npreparation will depend upon the type of cargo to be loaded. The vessel’s manager shall provide comprehensive hold cleaning\nguidelines, procedures, hold cleaning matrix for change of cargo and hold cleaning inspection checklist.\nCargo hold cleaning plans shall consist of the following steps, where applicable:\n1. Removal of dunnage, lashing material and/or cargo residues\n2. Holds swept down\n3. Holds swept down a second time (double swept)\n4. Cargo residues that have set hard removed\n5. Cleaning chemicals applied to hold surfaces and allowed to penetrate/react with stains prior to being washed off\n6. Holds washed down with sea water\n7. Holds washed down with detergents mixed in fresh water\n8. Holds rinsed with fresh water to remove all traces of chlorides and detergents\n9. Bilge wells and plates/strainers cleaned\n10. Holds air dried\n11. Loose paint flakes, loose rust scale and paint blisters removed\n12. Paintwork touched-up\n13. Barrier coat applied\nSome vessels are equipped with fixed cargo hold washing machines, however, these vessels are in a minority and most vessels\ncarrying solid bulk cargoes will need to manually wash the cargo holds. Where fixed washing machines are used, manual\ncleaning of shadow sectors within the holds may still be required. (Cargo Hold Cleaning, 2017)\nDuring the operation, the Master or Chief Officer should undertake inspections to ensure the cleaning is being carried out\ncorrectly using of the correct material and equipment. Inspections should be conducted at least once during each day by the\nMaster or Chief Officer accompanied by the Bosun, to establish how the operation is progressing.\nThe cargo hold cleaning checklist should be incorporated in the operator’s hold cleaning procedure.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.10","internal_question_no":"08B.010","question_sort_key":8201000.225,"question_text":"Have cargo holds been grain or hospital cleaned, where applicable, and has a ship’s hold inspection certificate been issued by a 3rd party prior to loading grain?","guide_to_inspection":"Hospital clean is the most stringent cleaning standard, requiring the holds to have 100% intact paint coatings on all surfaces,\nincluding the tank top, all ladder rungs and undersides of hatches. The standard of hospital clean is a requirement for certain\ncargoes, for example kaolin/china clay, mineral sands including zircon, barites, rutile sand, ilmenite, fluorspar, chrome ore, soda\nash, rice in bulk, and high grades of wood pulp. Generally, these high standards of cleanliness will only be met by vessels trading\nexclusively with such cargoes. It will rarely be required in the tramp trades.\nGrain clean is the most common requirement. A ship will be required to be grain clean for the majority of bulk and break bulk\ncargoes, such as all grains, soya meal and soya products, alumina, sulphur, bulk cement, bauxite, concentrates, and bulk\nfertilisers. Some ports and shippers may allow a different standard of cleanliness.\nThe industry accepted definition of grain clean is provided by the National Cargo Bureau (NCB).\n“Compartments are to be completely clean, dry, odour-free, and gas-free. All loose scale is to be removed.” The definition is\nclear:\n1. All past cargo residues and any lashing materials are to be removed from the hold\n2. Any loose paint or rust scale must be removed\n3. If it is necessary to wash the hold, as it generally will be, the holds must be dried after washing\n4. The hold must be well ventilated to ensure that it is odour-free and gas-free\nIt is important to differentiate such scale from oxidation rust (i.e. light atmospheric rusting). Loose scale will break away when\nstruck with a fist or when light pressure is applied with a knife blade or scraper under the edge of the scale. Oxidation rust will\ntypically form on bare metal surfaces but will not flake off when struck or when light pressure from a knife is applied. Generally,\nthe presence of hard-adhering scale within a hold is acceptable in a grain clean hold. The scale should not fall during the voyage\nor during normal cargo operations. (Bulk Cargoes Hold Preparation and Cleaning, 2011).\nThe 3rd party inspection company should be a member of the Grain and Feed Trade Association (GAFTA) or Federation of Oils,\nSeeds and Fat Associations (FOSFA) analyst and superintendent.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":123,"source_page_end":123,"raw_source_text":"Have cargo holds been grain or hospital cleaned, where applicable, and has a ship’s hold inspection\ncertificate been issued by a 3rd party prior to loading grain? (V & M)\nGuide to Inspection\nHospital clean is the most stringent cleaning standard, requiring the holds to have 100% intact paint coatings on all surfaces,\nincluding the tank top, all ladder rungs and undersides of hatches. The standard of hospital clean is a requirement for certain\ncargoes, for example kaolin/china clay, mineral sands including zircon, barites, rutile sand, ilmenite, fluorspar, chrome ore, soda\nash, rice in bulk, and high grades of wood pulp. Generally, these high standards of cleanliness will only be met by vessels trading\nexclusively with such cargoes. It will rarely be required in the tramp trades.\nGrain clean is the most common requirement. A ship will be required to be grain clean for the majority of bulk and break bulk\ncargoes, such as all grains, soya meal and soya products, alumina, sulphur, bulk cement, bauxite, concentrates, and bulk\nfertilisers. Some ports and shippers may allow a different standard of cleanliness.\nThe industry accepted definition of grain clean is provided by the National Cargo Bureau (NCB).\n“Compartments are to be completely clean, dry, odour-free, and gas-free. All loose scale is to be removed.” The definition is\nclear:\n1. All past cargo residues and any lashing materials are to be removed from the hold\n2. Any loose paint or rust scale must be removed\n3. If it is necessary to wash the hold, as it generally will be, the holds must be dried after washing\n4. The hold must be well ventilated to ensure that it is odour-free and gas-free\nIt is important to differentiate such scale from oxidation rust (i.e. light atmospheric rusting). Loose scale will break away when\nstruck with a fist or when light pressure is applied with a knife blade or scraper under the edge of the scale. Oxidation rust will\ntypically form on bare metal surfaces but will not flake off when struck or when light pressure from a knife is applied. Generally,\nthe presence of hard-adhering scale within a hold is acceptable in a grain clean hold. The scale should not fall during the voyage\nor during normal cargo operations. (Bulk Cargoes Hold Preparation and Cleaning, 2011).\nThe 3rd party inspection company should be a member of the Grain and Feed Trade Association (GAFTA) or Federation of Oils,\nSeeds and Fat Associations (FOSFA) analyst and superintendent.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.11","internal_question_no":"08B.011","question_sort_key":8201100.226,"question_text":"Is the vessel free of any limitations or restrictions specified in the loading manual or trim and stability booklet?","guide_to_inspection":"Important restrictions should be recorded in the inspector’s comments section. The ship shall be provided with an approved\nstability and loading booklet written in a language understood by the ship’s officers.\n(The Code of Practice for the Safe Loading and Unloading of Bulk Carriers, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":124,"source_page_end":124,"raw_source_text":"Is the vessel free of any limitations or restrictions specified in the loading manual or trim and\nstability booklet? (V)\nGuide to Inspection\nImportant restrictions should be recorded in the inspector’s comments section. The ship shall be provided with an approved\nstability and loading booklet written in a language understood by the ship’s officers.\n(The Code of Practice for the Safe Loading and Unloading of Bulk Carriers, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.12","internal_question_no":"08B.012","question_sort_key":8201200.227,"question_text":"Are officers familiar with the risk, hazard and carriage requirements of grain cargo on board the ship?","guide_to_inspection":"Shift of grain, contamination, ingress of water, moisture migration, and transfer of heat from engine room and / or bunker tank\nbulkhead and inadequate surface ventilation are the major risks and hazards associated with the handling grain cargo at sea.\nHeat can be transmitted from engine room to the aft cargo hold and subsequently affect the cargo loaded against the aft\nbulkhead. The pattern of damage in cargoes situated close to fuel tanks which have overheated will be obvious as grain will\ndiscolour and clump where there has been heat transfer. If possible, stow grain cargoes in holds which will not be affected by\nheated fuel tanks. Fuel oil temperature should be closely regulated and recorded during the voyage.\n(Carriage of Bulk Grain Cargoes, 2015)\nAs far as possible, the bunkers used during the voyage should be drawn from tanks situated well away from holds containing\nhygroscopic products. If impracticable, bunker tanks adjoining cargo spaces should be heated only when required, ensuring that\nthe temperature does not rise above normal operational levels. (Cargo Ventilation and Precautions to Minimise Sweat, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":124,"source_page_end":124,"raw_source_text":"Are officers familiar with the risk, hazard and carriage requirements of grain cargo on board the ship? (V)\nGuide to Inspection\nShift of grain, contamination, ingress of water, moisture migration, and transfer of heat from engine room and / or bunker tank\nbulkhead and inadequate surface ventilation are the major risks and hazards associated with the handling grain cargo at sea.\nHeat can be transmitted from engine room to the aft cargo hold and subsequently affect the cargo loaded against the aft\nbulkhead. The pattern of damage in cargoes situated close to fuel tanks which have overheated will be obvious as grain will\ndiscolour and clump where there has been heat transfer. If possible, stow grain cargoes in holds which will not be affected by\nheated fuel tanks. Fuel oil temperature should be closely regulated and recorded during the voyage.\n(Carriage of Bulk Grain Cargoes, 2015)\nAs far as possible, the bunkers used during the voyage should be drawn from tanks situated well away from holds containing\nhygroscopic products. If impracticable, bunker tanks adjoining cargo spaces should be heated only when required, ensuring that\nthe temperature does not rise above normal operational levels. (Cargo Ventilation and Precautions to Minimise Sweat, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.13","internal_question_no":"08B.013","question_sort_key":8201300.228,"question_text":"Have hatch covers been ultrasonically tested for weather tightness before loading?","guide_to_inspection":"Before loading it will always be prudent to have the hatches tested for weather tightness by ultrasonic testing.\n(Carriage of Grain Cargoes, 2015)\nThe technique is widely used throughout the industry to test and prove the weather tightness of hatch covers. The advantages\nof this method include:\n1. The test identifies the exact location and extent of leakage\n2. It indicates the compression status of the rubber seal; if compression is good, the rubber will be able to compensate for\nmovements at sea and maintain a tight seal\n3. The equipment is quick and easy to operate. One person operation is possible\n4. The test may be carried out in loaded or empty holds\n5. There are no weather/temperature limitations, and the test may be carried out during the day or night, and\n6. There is no pollution risk.\nThe procedure comprises placing a transmitter in the cargo hold, switching it on, and properly closing and securing the hatch\ncovers or access equipment to seaworthy requirements. The ultrasonic waves emitted by the transmitter within the enclosed\nspace will leak through the smallest of apertures. Any leakage of sound may be detected by a receiver or detector between\nfrequencies of 36.7 and 40.7 kHz and converted into aural frequencies or into digitally reproduced information. The location of\nleaks can be precisely detected from outside the hold by moving a hand-held detector along the periphery and cross seams of\nthe covers. Evaluation of the extent of leakage can be established from reading a digital scale.\n(UK P&I Club Carefully to Carry CONSOLIDATED EDITION 2018)\nThe use of ultrasonic equipment is a modern, viable means of testing for watertight integrity of hatch covers, access hatches,\ndoors, ventilators, etc. It is preferable to use Class approved equipment operated by qualified personnel and to follow approved\ntest procedures.\n(Steamshipmutual.com, 2004)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V & M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":124,"source_page_end":124,"raw_source_text":"Have hatch covers been ultrasonically tested for weather tightness before loading? (V & M)\nGuide to Inspection\nBefore loading it will always be prudent to have the hatches tested for weather tightness by ultrasonic testing.\n(Carriage of Grain Cargoes, 2015)\nThe technique is widely used throughout the industry to test and prove the weather tightness of hatch covers. The advantages\nof this method include:\n1. The test identifies the exact location and extent of leakage\n2. It indicates the compression status of the rubber seal; if compression is good, the rubber will be able to compensate for\nmovements at sea and maintain a tight seal\n3. The equipment is quick and easy to operate. One person operation is possible\n4. The test may be carried out in loaded or empty holds\n5. There are no weather/temperature limitations, and the test may be carried out during the day or night, and\n6. There is no pollution risk.\nThe procedure comprises placing a transmitter in the cargo hold, switching it on, and properly closing and securing the hatch\ncovers or access equipment to seaworthy requirements. The ultrasonic waves emitted by the transmitter within the enclosed\nspace will leak through the smallest of apertures. Any leakage of sound may be detected by a receiver or detector between\nfrequencies of 36.7 and 40.7 kHz and converted into aural frequencies or into digitally reproduced information. The location of\nleaks can be precisely detected from outside the hold by moving a hand-held detector along the periphery and cross seams of\nthe covers. Evaluation of the extent of leakage can be established from reading a digital scale.\n(UK P&I Club Carefully to Carry CONSOLIDATED EDITION 2018)\nThe use of ultrasonic equipment is a modern, viable means of testing for watertight integrity of hatch covers, access hatches,\ndoors, ventilators, etc. It is preferable to use Class approved equipment operated by qualified personnel and to follow approved\ntest procedures.\n(Steamshipmutual.com, 2004)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.14","internal_question_no":"08B.014","question_sort_key":8201400.229,"question_text":"Has the Master been provided with clear instructions regarding any fumigation, prior to arrival at the load port?","guide_to_inspection":"When a ship’s cargo is fumigated, the following recommendations should be observed:\n1- MSC.1/Circ.1264 – Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, as\namended by MSC.1/Circ.1396 (Amendment to the Recommendations on the Safe Use of Pesticides in Ships Applicable to the\nFumigation of Cargo Holds).\n2-MSC.1/Circ.1358 – Recommendations on the Safe Use of Pesticides in Ships.\n3-MSC.1/Circ.1361/Rev.1 – Revised Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of\nCargo Transport Units.\nSpaces connected to fumigated spaces should be treated as if fumigant gas could penetrate into them from the adjacent or\nconnected cargo space. Apart from the fatalities due to mistaken, unauthorized or accidental entry into cargo spaces under\nfumigation, a significant proportion of the fatal accidents that have occurred during in-transit cargo fumigation have resulted\nfrom fumigant gas leaking into ships’ accommodation areas, including cabins, as well as forecastle head spaces, ballast tanks,\nother adjacent spaces and on deck. The mishandling of fumigant materials has also caused fires and explosions on ships.\nContinuous monitoring of the atmosphere of connected and adjacent spaces that are designed for continuous occupation, or\nare frequently visited working areas, is recommended.\n(IMO, MSC.581(110), 2025)\nInstructions regarding the fumigation, the type of fumigation, who has requested the fumigation and what company will carry\nout the operation, should be provided for the Master. The Master should check through the instruction and if everything is in\norder and it is safe for the operation to be carried out, the fumigation should be allowed to go ahead.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe use of phosphine or any other fumigants is strictly forbidden by organic certification around the world. Currently, there are\nno organically approved fumigants that can be practically applied to organic bulk grain cargoes. As a result, all organic bulk\ncargoes must be transported without fumigation.\n(Carriage of Organic Bulk Grain Cargoes, 2015)\nMethyl bromide is an ozone-depleting chemical which was primarily used as a quarantine pesticide for soil, wood and grain.\nIt is fast acting and fumigation exposure times can be as little as 24 hours, however in-transit fumigation with methyl bromide\nis prohibited due to safety concerns and the crew must also leave the vessel in the event that a methyl bromide fumigation is\nundertaken at berth. This can incur additional costs associated with accommodating the crew and lead to concerns for owners\nand charterers about the safety of their vessel during this time.\nIn 1992, the Montreal Protocol described the initial strategy to phase out the use of methyl bromide as a pesticide. The strategy\nwas agreed by 160 countries. All developed countries agreed to a complete phase out of the chemical as a pesticide by 2005,\nwhile 2015 was the phase out date set for developing countries. Quarantine, pre-shipment, and critical uses of methyl bromide\nwere totally prohibited in the USA, UK and EU by 2010. While the phase out of methyl bromide should be 100% effective in\ndeveloping countries as of 1 January 2015, quarantine, pre-shipment, and critical uses of methyl bromide may be still permitted\nin certain circumstances.\n(Carriage of Grain Cargoes, 2015)\nThe crew should remain ashore until fumigation has been completed and a gas freeing certificate has been issued by the\nfumigator-in charge of the operation or by another authorised person. Methyl bromide is only approved for fumigation in port\nand should never be used for fumigation continued in transit. Methyl bromide will be introduced into the cargo compartments\nas a gas and effective fumigation of the cargo is likely to be achieved within 24 hours to 48 hours. If it is proposed that methyl\nbromide is to be used for fumigation of cargo in transit, the Master should not allow the operation to be carried out.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe task of ensuring cargo hold(s) integrity should not be taken lightly as this operation is key to ensuring crew safety. The\ncompany should establish procedures, plans and instructions, including appropriate checklists, for key shipboard operations\nconcerning the safety of the personnel, ship and protection of the environment. The various tasks should be defined and\nassigned to qualified personnel, and the vessel should have procedures in place in their safety management system on how to\nhandle fumigation jobs onboard.\nIt is strongly recommended that special attention is given to potential leakages from and/or through:\n> Cable locks\n> Ventilation systems\n> Ballast systems\n> Duct keels\n> Bilges\n> Wiring ducts\n> Dehumidifiers\n> Compartments of the engine room\n> Any other sort of piping arrangements connected to parts of the cargo hold\n(Fumigants entering crew’s spaces – a word of caution, 2020)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":125,"source_page_end":125,"raw_source_text":"Has the Master been provided with clear instructions regarding any fumigation, prior to arrival at\nthe load port? (V)\nGuide to Inspection\nWhen a ship’s cargo is fumigated, the following recommendations should be observed:\n1- MSC.1/Circ.1264 – Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, as\namended by MSC.1/Circ.1396 (Amendment to the Recommendations on the Safe Use of Pesticides in Ships Applicable to the\nFumigation of Cargo Holds).\n2-MSC.1/Circ.1358 – Recommendations on the Safe Use of Pesticides in Ships.\n3-MSC.1/Circ.1361/Rev.1 – Revised Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of\nCargo Transport Units.\nSpaces connected to fumigated spaces should be treated as if fumigant gas could penetrate into them from the adjacent or\nconnected cargo space. Apart from the fatalities due to mistaken, unauthorized or accidental entry into cargo spaces under\nfumigation, a significant proportion of the fatal accidents that have occurred during in-transit cargo fumigation have resulted\nfrom fumigant gas leaking into ships’ accommodation areas, including cabins, as well as forecastle head spaces, ballast tanks,\nother adjacent spaces and on deck. The mishandling of fumigant materials has also caused fires and explosions on ships.\nContinuous monitoring of the atmosphere of connected and adjacent spaces that are designed for continuous occupation, or\nare frequently visited working areas, is recommended.\n(IMO, MSC.581(110), 2025)\nInstructions regarding the fumigation, the type of fumigation, who has requested the fumigation and what company will carry\nout the operation, should be provided for the Master. The Master should check through the instruction and if everything is in\norder and it is safe for the operation to be carried out, the fumigation should be allowed to go ahead.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe use of phosphine or any other fumigants is strictly forbidden by organic certification around the world. Currently, there are\nno organically approved fumigants that can be practically applied to organic bulk grain cargoes. As a result, all organic bulk\ncargoes must be transported without fumigation.\n(Carriage of Organic Bulk Grain Cargoes, 2015)\nMethyl bromide is an ozone-depleting chemical which was primarily used as a quarantine pesticide for soil, wood and grain.\nIt is fast acting and fumigation exposure times can be as little as 24 hours, however in-transit fumigation with methyl bromide\nis prohibited due to safety concerns and the crew must also leave the vessel in the event that a methyl bromide fumigation is\nundertaken at berth. This can incur additional costs associated with accommodating the crew and lead to concerns for owners\nand charterers about the safety of their vessel during this time.\nIn 1992, the Montreal Protocol described the initial strategy to phase out the use of methyl bromide as a pesticide. The strategy\nwas agreed by 160 countries. All developed countries agreed to a complete phase out of the chemical as a pesticide by 2005,\nwhile 2015 was the phase out date set for developing countries. Quarantine, pre-shipment, and critical uses of methyl bromide\nwere totally prohibited in the USA, UK and EU by 2010. While the phase out of methyl bromide should be 100% effective in\ndeveloping countries as of 1 January 2015, quarantine, pre-shipment, and critical uses of methyl bromide may be still permitted\nin certain circumstances.\n(Carriage of Grain Cargoes, 2015)\nThe crew should remain ashore until fumigation has been completed and a gas freeing certificate has been issued by the\nfumigator-in charge of the operation or by another authorised person. Methyl bromide is only approved for fumigation in port\nand should never be used for fumigation continued in transit. Methyl bromide will be introduced into the cargo compartments\nas a gas and effective fumigation of the cargo is likely to be achieved within 24 hours to 48 hours. If it is proposed that methyl\nbromide is to be used for fumigation of cargo in transit, the Master should not allow the operation to be carried out.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe task of ensuring cargo hold(s) integrity should not be taken lightly as this operation is key to ensuring crew safety. The\ncompany should establish procedures, plans and instructions, including appropriate checklists, for key shipboard operations\nconcerning the safety of the personnel, ship and protection of the environment. The various tasks should be defined and\nassigned to qualified personnel, and the vessel should have procedures in place in their safety management system on how to\nhandle fumigation jobs onboard.\nIt is strongly recommended that special attention is given to potential leakages from and/or through:\n> Cable locks\n> Ventilation systems\n> Ballast systems\n> Duct keels\n> Bilges\n> Wiring ducts\n> Dehumidifiers\n> Compartments of the engine room\n> Any other sort of piping arrangements connected to parts of the cargo hold\n(Fumigants entering crew’s spaces – a word of caution, 2020)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.15","internal_question_no":"08B.015","question_sort_key":8201500.23,"question_text":"Has the vessel been provided with procedures and contingencies regarding fumigation of cargo holds and are the Master and Chief Officer familiar with the procedure?","guide_to_inspection":"The Master should familiarize themselves with the recommendations set out in the procedures given in the SMS manual and\nwith the guidance set out in section 3 of MSC.1/Circ.1264. In addition, some individual countries, for example the USA and\nCanada, have produced their own requirements which should be followed when fumigation is being carried out on board a ship\nwithin their territorial waters; the Master should be familiar with these requirements if appropriate.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":126,"source_page_end":126,"raw_source_text":"Has the vessel been provided with procedures and contingencies regarding fumigation of cargo\nholds and are the Master and Chief Officer familiar with the procedure? (V)\nGuide to Inspection\nThe Master should familiarize themselves with the recommendations set out in the procedures given in the SMS manual and\nwith the guidance set out in section 3 of MSC.1/Circ.1264. In addition, some individual countries, for example the USA and\nCanada, have produced their own requirements which should be followed when fumigation is being carried out on board a ship\nwithin their territorial waters; the Master should be familiar with these requirements if appropriate.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.16","internal_question_no":"08B.016","question_sort_key":8201600.231,"question_text":"Is crew familiar with major problems associated with fumigation of cargo in stowage on board?","guide_to_inspection":"With respect to the use of phosphine, there are three major problems with the fumigation of cargo in stowage on board, these\nbeing its toxicity, its potential for fire or explosion and its effectiveness. The fumigation gas is toxic to insects but is also toxic\nto human and other animals. This being the case, safety of the crew, the operatives carrying out the fumigating operation, and\nother personnel on board must be ensured by following procedures strictly.\nAfter the pellets or tablets have been distributed within the cargo or cargo compartment, they will react with the atmospheric\nmoisture to produce the fumigant gas. The chemical reaction will also produce heat. If the fumigant is not distributed correctly,\nfor example, is placed in piles rather than being spread around, the heat produced might cause heating of adjacent cargo which\nmay produce combustion and fire. Alternatively, in extreme case, an explosion might be the result of spontaneous heating of the\nfumigation gas as phosphine gas is explosive at levels above 1.7% v/v in air. If the pellets or tablets become wet, for example by\nsea water ingress, rain or condensation, they can spontaneously ignite.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":126,"source_page_end":126,"raw_source_text":"Is crew familiar with major problems associated with fumigation of cargo in stowage on board? (V)\nGuide to Inspection\nWith respect to the use of phosphine, there are three major problems with the fumigation of cargo in stowage on board, these\nbeing its toxicity, its potential for fire or explosion and its effectiveness. The fumigation gas is toxic to insects but is also toxic\nto human and other animals. This being the case, safety of the crew, the operatives carrying out the fumigating operation, and\nother personnel on board must be ensured by following procedures strictly.\nAfter the pellets or tablets have been distributed within the cargo or cargo compartment, they will react with the atmospheric\nmoisture to produce the fumigant gas. The chemical reaction will also produce heat. If the fumigant is not distributed correctly,\nfor example, is placed in piles rather than being spread around, the heat produced might cause heating of adjacent cargo which\nmay produce combustion and fire. Alternatively, in extreme case, an explosion might be the result of spontaneous heating of the\nfumigation gas as phosphine gas is explosive at levels above 1.7% v/v in air. If the pellets or tablets become wet, for example by\nsea water ingress, rain or condensation, they can spontaneously ignite.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.17","internal_question_no":"08B.017","question_sort_key":8201700.232,"question_text":"Do on-board safety requirements for fumigation comply with sub-section 3.3.2.7 of the IMO recommendation on the safe use of pesticides?","guide_to_inspection":"The ship should carry:\n> Gas-detection equipment and adequate fresh supplies of service items for the fumigant(s) concerned as required by\n3.3.2.12, together with instructions for its use and the occupational exposure limit values set by the Flag State regulations\nfor safe working conditions.\n> Instructions on disposal of residual fumigant material.\n> At least four sets of adequate respiratory protective equipment; and\n> A copy of the latest version of the Medical First Aid Guide for Use in Accidents Involving Dangerous Goods (MFAG),\nincluding appropriate medicines and medical equipment.\n(Recommendations on the safe use of pesticides in ships applicable to the fumigation of cargo holds, 2008)\nIt is reported that phosphine gas can be detected because it smells of garlic. This is not a reliable method, and the absence of a\ngarlic smell does not mean the absence of phosphine gas. The only reliable method of detecting phosphine gas is by the use of\nthe gas detection equipment which is on board for the purpose.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":126,"source_page_end":126,"raw_source_text":"Do on-board safety requirements for fumigation comply with sub-section 3.3.2.7 of the IMO\nrecommendation on the safe use of pesticides? (V)\nGuide to Inspection\nThe ship should carry:\n> Gas-detection equipment and adequate fresh supplies of service items for the fumigant(s) concerned as required by\n3.3.2.12, together with instructions for its use and the occupational exposure limit values set by the Flag State regulations\nfor safe working conditions.\n> Instructions on disposal of residual fumigant material.\n> At least four sets of adequate respiratory protective equipment; and\n> A copy of the latest version of the Medical First Aid Guide for Use in Accidents Involving Dangerous Goods (MFAG),\nincluding appropriate medicines and medical equipment.\n(Recommendations on the safe use of pesticides in ships applicable to the fumigation of cargo holds, 2008)\nIt is reported that phosphine gas can be detected because it smells of garlic. This is not a reliable method, and the absence of a\ngarlic smell does not mean the absence of phosphine gas. The only reliable method of detecting phosphine gas is by the use of\nthe gas detection equipment which is on board for the purpose.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.18","internal_question_no":"08B.018","question_sort_key":8201800.233,"question_text":"Are the Master’s appointed representatives for fumigation trained and is there evidence to show that they have been effectively performing duties associated with this task?","guide_to_inspection":"Before fumigation is conducted, one officer and one crew member, both of whom have been trained (i.e. shown the information\non the fumigant Safety Data Sheet and the instructions for fumigant use), should be designated as the “trained representatives\nof the Master”. These representatives must:\n> Brief the crew before a fumigation takes place and satisfy the fumigator-in-charge that this has been done.\n> Inspect and/or test empty cargo holds for leakage with instruments so that proper sealing can be done before or after\nloading. The fumigator-in-charge, accompanied by a trained representative of the Master or a competent person, should\ndetermine whether the cargo holds to be treated are or can be made sufficiently gastight to prevent leakage of the\nfumigant to the accommodation, engine-rooms and other working spaces in the ship. Special attention should be paid to\npotential problem areas such as bilge and cargo line systems.\n> Continue monitoring in the accommodation, engine room, etc. Though the initial check may not indicate any leaks, it is\nessential that monitoring is to be continued because concentrations may reach their highest levels after several days.\nContinue monitoring the gas levels in accommodation and working spaces after the fumigator has left the ship.\n(Recommendations on the safe use of pesticides in ships applicable to the fumigation of cargo holds, 2008)\nThe Master representatives should be trained with regard to gas concentration checks which must be carried out before\ndeparture and during the voyage, where and when those checks must be done and what records must be kept to comply with\nother parts of the requirements.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":127,"source_page_end":127,"raw_source_text":"Are the Master’s appointed representatives for fumigation trained and is there evidence to show\nthat they have been effectively performing duties associated with this task? (V)\nGuide to Inspection\nBefore fumigation is conducted, one officer and one crew member, both of whom have been trained (i.e. shown the information\non the fumigant Safety Data Sheet and the instructions for fumigant use), should be designated as the “trained representatives\nof the Master”. These representatives must:\n> Brief the crew before a fumigation takes place and satisfy the fumigator-in-charge that this has been done.\n> Inspect and/or test empty cargo holds for leakage with instruments so that proper sealing can be done before or after\nloading. The fumigator-in-charge, accompanied by a trained representative of the Master or a competent person, should\ndetermine whether the cargo holds to be treated are or can be made sufficiently gastight to prevent leakage of the\nfumigant to the accommodation, engine-rooms and other working spaces in the ship. Special attention should be paid to\npotential problem areas such as bilge and cargo line systems.\n> Continue monitoring in the accommodation, engine room, etc. Though the initial check may not indicate any leaks, it is\nessential that monitoring is to be continued because concentrations may reach their highest levels after several days.\nContinue monitoring the gas levels in accommodation and working spaces after the fumigator has left the ship.\n(Recommendations on the safe use of pesticides in ships applicable to the fumigation of cargo holds, 2008)\nThe Master representatives should be trained with regard to gas concentration checks which must be carried out before\ndeparture and during the voyage, where and when those checks must be done and what records must be kept to comply with\nother parts of the requirements.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.19","internal_question_no":"08B.019","question_sort_key":8201900.234,"question_text":"Have pre-fumigation and post fumigation statements been provided to the Master by the fumigator-in-charge?","guide_to_inspection":"The fumigator-in-charge, together with a trained representative, should carry out inspections and/or tests of cargo\ncompartments to determine whether the holds to be treated can be made sufficiently gas-tight to prevent leakage of the\nfumigant from the holds into other compartments. Following such inspections, further discussion should be held between the\nMaster and fumigator-in-charge, and the fumigator-in-charge should provide the Master with a signed document stating the\nfollowing:\n> Details of inspections and tests conducted\n> Details of provisions and preparations for fumigation made\n> Confirmation that holds to be treated are or can be made satisfactorily gas tight for the fumigation.\nIf any holds cannot be made sufficiently gas-tight, a signed statement to this effect should also be supplied to the Master. The\nfumigator-in-charge should notify the Master, in writing, which cargo spaces are to be fumigated and which other spaces are\nconsidered to be unsafe.\nThe fumigator-in-charge, together with the trained representative of the Master should make an initial check for any gas leaks,\nusing the gas detection equipment, around the hatches and if any leaks are found they should be sealed using appropriate material.\nAt an appropriate time after application of the fumigant, the fumigator-in-charge, accompanied by a representative of the Master,\nshould check that accommodation, engine-rooms, and other working spaces remain free of harmful concentrations of gas.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)\nWhen fumigators-in-charge are satisfied that the application of fumigation and the sealing of hatches has been completed,\nthey should formally hand over to the Master in writing responsibility for maintaining safe conditions in all occupied spaces. The\nsigned written statement should include following:\n> List of documents provided.\n> Confirmation that all spaces adjacent to treated spaces have been found gas free.\n> Confirmation that trained representative are fully conversant with the use of the gas detection equipment.\n> Confirmation that gas detection equipment and the respiratory equipment is in full working order.\n> Confirmation that adequate supplies of consumables for the equipment are available on board.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe Master and fumigator-in-charge, or their representatives, should complete and sign the model checklist for in-transit\nfumigation.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":127,"source_page_end":127,"raw_source_text":"Have pre-fumigation and post fumigation statements been provided to the Master by the\nfumigator-in-charge? (V)\nGuide to Inspection\nThe fumigator-in-charge, together with a trained representative, should carry out inspections and/or tests of cargo\ncompartments to determine whether the holds to be treated can be made sufficiently gas-tight to prevent leakage of the\nfumigant from the holds into other compartments. Following such inspections, further discussion should be held between the\nMaster and fumigator-in-charge, and the fumigator-in-charge should provide the Master with a signed document stating the\nfollowing:\n> Details of inspections and tests conducted\n> Details of provisions and preparations for fumigation made\n> Confirmation that holds to be treated are or can be made satisfactorily gas tight for the fumigation.\nIf any holds cannot be made sufficiently gas-tight, a signed statement to this effect should also be supplied to the Master. The\nfumigator-in-charge should notify the Master, in writing, which cargo spaces are to be fumigated and which other spaces are\nconsidered to be unsafe.\nThe fumigator-in-charge, together with the trained representative of the Master should make an initial check for any gas leaks,\nusing the gas detection equipment, around the hatches and if any leaks are found they should be sealed using appropriate material.\nAt an appropriate time after application of the fumigant, the fumigator-in-charge, accompanied by a representative of the Master,\nshould check that accommodation, engine-rooms, and other working spaces remain free of harmful concentrations of gas.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)\nWhen fumigators-in-charge are satisfied that the application of fumigation and the sealing of hatches has been completed,\nthey should formally hand over to the Master in writing responsibility for maintaining safe conditions in all occupied spaces. The\nsigned written statement should include following:\n> List of documents provided.\n> Confirmation that all spaces adjacent to treated spaces have been found gas free.\n> Confirmation that trained representative are fully conversant with the use of the gas detection equipment.\n> Confirmation that gas detection equipment and the respiratory equipment is in full working order.\n> Confirmation that adequate supplies of consumables for the equipment are available on board.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe Master and fumigator-in-charge, or their representatives, should complete and sign the model checklist for in-transit\nfumigation.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.20","internal_question_no":"08B.020","question_sort_key":8202000.235,"question_text":"Are visible means provided to prevent access to all entrances containing fumigant and other spaces that are considered unsafe to enter after fumigation?","guide_to_inspection":"On application of the fumigant, the fumigator-in-charge should post warning signs at all entrances to places notified to the\nMaster as in 3.3.2.8 of MSC.1/Circ.1264. These warning signs should indicate the identity of the fumigant and the date and time\nof fumigation.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":128,"source_page_end":128,"raw_source_text":"Are visible means provided to prevent access to all entrances containing fumigant and other\nspaces that are considered unsafe to enter after fumigation? (V)\nGuide to Inspection\nOn application of the fumigant, the fumigator-in-charge should post warning signs at all entrances to places notified to the\nMaster as in 3.3.2.8 of MSC.1/Circ.1264. These warning signs should indicate the identity of the fumigant and the date and time\nof fumigation.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.21","internal_question_no":"08B.021","question_sort_key":8202100.236,"question_text":"Has the Voyage Safety Plan (VSP), including the checklist for fumigation during the voyage, been discussed with and signed by the Master prior to sailing to the discharge port?","guide_to_inspection":"The Voyage Safety Plan (VSP) including checklist confirming the following:\nBefore fumigant application\n> The inspection required before loading has been performed.\n> All the cargo spaces to be fumigated are satisfactory for fumigation.\n> Spaces, where found not be satisfactory, have been sealed.\n> The Master or his trained representatives have been made aware of the specific areas to be checked for gas\nconcentrations throughout the fumigation period.\n> The Master or his trained representatives have been made familiar with the fumigant label, detection methods, safety\nprocedures and emergency procedures.\n> The fumigator-in-charge has ensured that gas-detection and respiratory protection equipment carried on the ship is in\ngood order, and that adequate fresh supplies of consumable items for this equipment are available to allow sampling.\nThe fumigator-in-charge has ensured that the necessary medicines and medical equipment, and the latest version of the\nMedical First Aid Guide for Use in Accident Involving Dangerous Goods (MFAG) are available on board the ship.\nThe Master has been notified in writing of:\n> The spaces containing cargo to be fumigated.\n> Any other spaces that are considered unsafe to enter during the fumigation.\nAfter fumigant application\nPresence of gas has been confirmed inside each hold under fumigation.\n> Each hold has been checked for leakage and sealed properly.\n> Spaces adjacent to the treated cargo spaces have been checked and found gas-free.\n> The responsible crew members have been shown how to take gas readings properly when gas is present and they are fully\nconversant with the use of gas-detection equipment provided;\n> Methods of application are described.\n> The Master or trained representatives have been briefed fully on the method of application and the spread of the gas\nthroughout the hold.\nThe Master or trained representatives have been made:\n> Aware that even though the initial check may not indicate any leaks, it is essential that monitoring is to be continued in the\naccommodation, engine-room, etc. because concentrations may reach their highest levels after several days.\n> Aware of the possibility of the spreading of gas throughout the duct keel and/or ballast tanks.\n> Aware that the Master is responsible for all aspects of the safety of the fumigation once the “fumigator-in-charge” has\nformally handed over responsibility to them and left the vessel.\n> The fumigator-in-charge has supplied a signed statement to the Master conforming to the provisions of IMO\nRecommendations.\n(Code of Practice on Safety and Efficacy for Marine Fumigation, 2010)\nDegassing and checking results at the discharge port – should be done according to the guidance given by the fumigator in\ncharge at the load port and included with the VSP. For example, there should be clear written instructions on how to handle and\ndispose of any fumigant containers or fumigation residues.\n(Carriage of Grain Cargoes, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":128,"source_page_end":128,"raw_source_text":"Has the Voyage Safety Plan (VSP), including the checklist for fumigation during the voyage, been\ndiscussed with and signed by the Master prior to sailing to the discharge port? (V)\nGuide to Inspection\nThe Voyage Safety Plan (VSP) including checklist confirming the following:\nBefore fumigant application\n> The inspection required before loading has been performed.\n> All the cargo spaces to be fumigated are satisfactory for fumigation.\n> Spaces, where found not be satisfactory, have been sealed.\n> The Master or his trained representatives have been made aware of the specific areas to be checked for gas\nconcentrations throughout the fumigation period.\n> The Master or his trained representatives have been made familiar with the fumigant label, detection methods, safety\nprocedures and emergency procedures.\n> The fumigator-in-charge has ensured that gas-detection and respiratory protection equipment carried on the ship is in\ngood order, and that adequate fresh supplies of consumable items for this equipment are available to allow sampling.\nThe fumigator-in-charge has ensured that the necessary medicines and medical equipment, and the latest version of the\nMedical First Aid Guide for Use in Accident Involving Dangerous Goods (MFAG) are available on board the ship.\nThe Master has been notified in writing of:\n> The spaces containing cargo to be fumigated.\n> Any other spaces that are considered unsafe to enter during the fumigation.\nAfter fumigant application\nPresence of gas has been confirmed inside each hold under fumigation.\n> Each hold has been checked for leakage and sealed properly.\n> Spaces adjacent to the treated cargo spaces have been checked and found gas-free.\n> The responsible crew members have been shown how to take gas readings properly when gas is present and they are fully\nconversant with the use of gas-detection equipment provided;\n> Methods of application are described.\n> The Master or trained representatives have been briefed fully on the method of application and the spread of the gas\nthroughout the hold.\nThe Master or trained representatives have been made:\n> Aware that even though the initial check may not indicate any leaks, it is essential that monitoring is to be continued in the\naccommodation, engine-room, etc. because concentrations may reach their highest levels after several days.\n> Aware of the possibility of the spreading of gas throughout the duct keel and/or ballast tanks.\n> Aware that the Master is responsible for all aspects of the safety of the fumigation once the “fumigator-in-charge” has\nformally handed over responsibility to them and left the vessel.\n> The fumigator-in-charge has supplied a signed statement to the Master conforming to the provisions of IMO\nRecommendations.\n(Code of Practice on Safety and Efficacy for Marine Fumigation, 2010)\nDegassing and checking results at the discharge port – should be done according to the guidance given by the fumigator in\ncharge at the load port and included with the VSP. For example, there should be clear written instructions on how to handle and\ndispose of any fumigant containers or fumigation residues.\n(Carriage of Grain Cargoes, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.22","internal_question_no":"08B.022","question_sort_key":8202200.237,"question_text":"Have the air conditioning intakes for the accommodation, the engine room and other spaces been set to prevent the possibility of drawing in fumigant gas?","guide_to_inspection":"Ventilation procedures for accommodation, the engine room and other spaces should be reviewed to avoid the possibility\nof drawing fumigant gas into those spaces by incorrect ventilation. Further, it should be verified that ventilation flaps and\nclosing devices are correctly set before the fumigation is carried out and they should be maintained in the correct arrangement\nthroughout the fumigation period. A review of the ventilation regime should be completed before any ventilation of the cargo\ncompartment is started and any necessary changes to those arrangements should be made.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":129,"source_page_end":129,"raw_source_text":"Have the air conditioning intakes for the accommodation, the engine room and other spaces been\nset to prevent the possibility of drawing in fumigant gas? (V)\nGuide to Inspection\nVentilation procedures for accommodation, the engine room and other spaces should be reviewed to avoid the possibility\nof drawing fumigant gas into those spaces by incorrect ventilation. Further, it should be verified that ventilation flaps and\nclosing devices are correctly set before the fumigation is carried out and they should be maintained in the correct arrangement\nthroughout the fumigation period. A review of the ventilation regime should be completed before any ventilation of the cargo\ncompartment is started and any necessary changes to those arrangements should be made.\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.23","internal_question_no":"08B.023","question_sort_key":8202300.238,"question_text":"Are procedures in place for entering any cargo holds sealed for fumigation in transit?","guide_to_inspection":"Except in extreme emergency, cargo holds sealed for fumigation in transit should never be opened at sea or entered. If entry is\nimperative, at least two persons should enter, wearing adequate protection equipment and a safety harness and lifeline tended\nby a person outside the space, similarly equipped with protective, self-contained breathing apparatus.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":129,"source_page_end":129,"raw_source_text":"Are procedures in place for entering any cargo holds sealed for fumigation in transit? (V)\nGuide to Inspection\nExcept in extreme emergency, cargo holds sealed for fumigation in transit should never be opened at sea or entered. If entry is\nimperative, at least two persons should enter, wearing adequate protection equipment and a safety harness and lifeline tended\nby a person outside the space, similarly equipped with protective, self-contained breathing apparatus.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.24","internal_question_no":"08B.024","question_sort_key":8202400.239,"question_text":"Has the Master informed the appropriate authorities of the country of destination about the fumigation?","guide_to_inspection":"Prior to the arrival of the ship, generally not less than 24 hours in advance, the Master should inform the appropriate authorities\nof the country of destination and ports of call that fumigation in transit has been carried out. The information should include\nthe type of fumigant used, the date of fumigation, the cargo holds which have been fumigated, and whether ventilation has\ncommenced.\nUpon arrival at the port of discharge, the Master should also provide information about use of the fumigant, e.g., on the fumigant\nlabel or package itself, such as the recommendations of the fumigant manufacturer concerning methods of detection of the\nfumigant in air, its behaviour and hazardous properties, symptoms of poisoning, relevant first aid, special medical treatment,\nemergency procedures and instructions on disposal of residual fumigant material.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":129,"source_page_end":129,"raw_source_text":"Has the Master informed the appropriate authorities of the country of destination about the fumigation? (V)\nGuide to Inspection\nPrior to the arrival of the ship, generally not less than 24 hours in advance, the Master should inform the appropriate authorities\nof the country of destination and ports of call that fumigation in transit has been carried out. The information should include\nthe type of fumigant used, the date of fumigation, the cargo holds which have been fumigated, and whether ventilation has\ncommenced.\nUpon arrival at the port of discharge, the Master should also provide information about use of the fumigant, e.g., on the fumigant\nlabel or package itself, such as the recommendations of the fumigant manufacturer concerning methods of detection of the\nfumigant in air, its behaviour and hazardous properties, symptoms of poisoning, relevant first aid, special medical treatment,\nemergency procedures and instructions on disposal of residual fumigant material.\n(Recommendations on the Safe Use of Pesticides in Ships Applicable to the Fumigation of Cargo Holds, 2008)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.25","internal_question_no":"08B.025","question_sort_key":8202500.24,"question_text":"Did the vessel receive a fumigant gas-free certificate issued by the fumigator-in-charge at or prior to the discharge port or, in the absence of a gas-free certificate did the Master implement appropriate safety measures to manage potential residual fumigant risks before and during discharge operations?","guide_to_inspection":"Before discharge of grain cargoes can be approved, holds that have been subject to fumigation will have to be declared gas free.\nThis is to ensure the holds are free from any gas that may make the holds unsafe.\nAfter the holds have been declared gas free, the surfaces of the cargo may be subject to visual inspection. This can be carried\nout by the receiver, port officials and/or government inspectors as the hatches are open, prior to the approval of discharge.\n(Carriage of Organic Bulk Grain Cargoes, 2015)\nFumigants are acutely toxic substances. Exposure to high concentrations can cause immediate and severe health effects.\nRelying solely on periodic atmospheric monitoring may not detect the presence of fumigants in time to prevent fatal exposure.\n(ICHCA International, 2025)\nMaster’s Responsibilities\nWhere informed that a representative of the fumigation company is not available at the discharge port, and a gas-free certificate\nconfirming the safe condition of the cargo holds and surrounding areas has not been issued, the Master should:\n> Immediately notify both the Port Authority and the Ship Manager clearly communicating the absence of gas-free\ncertification and any associated safety concerns, following any instructions provided precisely.\n> Document all communications and actions taken.\n> Conduct a specific risk assessment prior to discharge operations, then based on the assessment determine and provide\nappropriate PPE which should protect against fumigant gases as well as other potential hazards, such as oxygen\ndepletion.\n> Secure all entrances to unattended or hazardous areas to prevent unauthorized access.\nEnsure that ongoing atmospheric testing is conducted at regular and frequent intervals using calibrated and certified equipment\nspecific to the fumigant in use.\n> Empower crew members to stop any unsafe activity or behaviour by visitors or contractors that could lead to an incident.\nShip Manager Responsibilities\nVessel managers should be prepared for situations where a fumigation company’s representative or fumigator-in-charge is\nunavailable at the discharge port. In such cases, they should:\n> Ensure The SMS should provide clear and explicit operational guidelines to ensure the safe conduct of cargo operations.\n> Support the Master in implementing appropriate safety measures","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":130,"source_page_end":130,"raw_source_text":"Did the vessel receive a fumigant gas-free certificate issued by the fumigator-in-charge at or prior to the discharge\nport or, in the absence of a gas-free certificate did the Master implement appropriate safety measures to manage\npotential residual fumigant risks before and during discharge operations? (V)\nGuide to Inspection\nBefore discharge of grain cargoes can be approved, holds that have been subject to fumigation will have to be declared gas free.\nThis is to ensure the holds are free from any gas that may make the holds unsafe.\nAfter the holds have been declared gas free, the surfaces of the cargo may be subject to visual inspection. This can be carried\nout by the receiver, port officials and/or government inspectors as the hatches are open, prior to the approval of discharge.\n(Carriage of Organic Bulk Grain Cargoes, 2015)\nFumigants are acutely toxic substances. Exposure to high concentrations can cause immediate and severe health effects.\nRelying solely on periodic atmospheric monitoring may not detect the presence of fumigants in time to prevent fatal exposure.\n(ICHCA International, 2025)\nMaster’s Responsibilities\nWhere informed that a representative of the fumigation company is not available at the discharge port, and a gas-free certificate\nconfirming the safe condition of the cargo holds and surrounding areas has not been issued, the Master should:\n> Immediately notify both the Port Authority and the Ship Manager clearly communicating the absence of gas-free\ncertification and any associated safety concerns, following any instructions provided precisely.\n> Document all communications and actions taken.\n> Conduct a specific risk assessment prior to discharge operations, then based on the assessment determine and provide\nappropriate PPE which should protect against fumigant gases as well as other potential hazards, such as oxygen\ndepletion.\n> Secure all entrances to unattended or hazardous areas to prevent unauthorized access.\nEnsure that ongoing atmospheric testing is conducted at regular and frequent intervals using calibrated and certified equipment\nspecific to the fumigant in use.\n> Empower crew members to stop any unsafe activity or behaviour by visitors or contractors that could lead to an incident.\nShip Manager Responsibilities\nVessel managers should be prepared for situations where a fumigation company’s representative or fumigator-in-charge is\nunavailable at the discharge port. In such cases, they should:\n> Ensure The SMS should provide clear and explicit operational guidelines to ensure the safe conduct of cargo operations.\n> Support the Master in implementing appropriate safety measures","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.26","internal_question_no":"08B.026","question_sort_key":8202600.241,"question_text":"Are records maintained of fumigation operations?","guide_to_inspection":"Records for fumigation of cargo:\n> Communication relating to fumigation\n> Details of fumigation company, fumigator-in-charge, and operation\n> Fumigation plan\n> In the deck logbook record details of the operation\n> In a workbook record details of the operation including:\n- Details of the fumigator-in-charge and operatives.\n- Time of starting and finishing.\n- Holds involved.\n- Identity of the fumigant, application level and where and how applied.\n- All gas reading with location testing.\n> Plan and sketch for each hold fumigated, showing where the fumigant was applied and the amount of fumigant at each\nlocation.\n> Model checklist for in-transit fumigation signed by the Master and the fumigator-in-charge.\n> Certificate of fumigation\n> Formal written handover of responsibility.\nRecords relating to fumigation for each day:\n> Gas concentration readings obtained and location at which each reading was taken\n> Gas concentration safety checks at all appropriate locations, which should at least include:\n- Accommodation\n- Engine-rooms\n- Areas designated for use in the navigation of the ship\n- Frequently visited working areas and stores, such as the forecastle head spaces adjacent to cargo holds being subject to\nfumigation in transit should be continued\n- Throughout the voyage at least at eight-hour intervals or more frequently if so advised by the fumigator-in-charge. These\nreadings should be recorded in the ship’s logbook.\n> Time readings taken\n> Any action necessary because of high readings\n> Results of action taken\n> Details of ventilation holds after fumigation period\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":130,"source_page_end":130,"raw_source_text":"Are records maintained of fumigation operations? (V)\nGuide to Inspection\nRecords for fumigation of cargo:\n> Communication relating to fumigation\n> Details of fumigation company, fumigator-in-charge, and operation\n> Fumigation plan\n> In the deck logbook record details of the operation\n> In a workbook record details of the operation including:\n- Details of the fumigator-in-charge and operatives.\n- Time of starting and finishing.\n- Holds involved.\n- Identity of the fumigant, application level and where and how applied.\n- All gas reading with location testing.\n> Plan and sketch for each hold fumigated, showing where the fumigant was applied and the amount of fumigant at each\nlocation.\n> Model checklist for in-transit fumigation signed by the Master and the fumigator-in-charge.\n> Certificate of fumigation\n> Formal written handover of responsibility.\nRecords relating to fumigation for each day:\n> Gas concentration readings obtained and location at which each reading was taken\n> Gas concentration safety checks at all appropriate locations, which should at least include:\n- Accommodation\n- Engine-rooms\n- Areas designated for use in the navigation of the ship\n- Frequently visited working areas and stores, such as the forecastle head spaces adjacent to cargo holds being subject to\nfumigation in transit should be continued\n- Throughout the voyage at least at eight-hour intervals or more frequently if so advised by the fumigator-in-charge. These\nreadings should be recorded in the ship’s logbook.\n> Time readings taken\n> Any action necessary because of high readings\n> Results of action taken\n> Details of ventilation holds after fumigation period\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.27","internal_question_no":"08B.027","question_sort_key":8202700.242,"question_text":"Are necessary instruments (with spare) to determine the dew point provided, maintained in good condition and are there records of the calibration of such instruments?","guide_to_inspection":"Dewpoint temperature may be measured by a variety of methods. Ships generally use a traditional wet and dry bulb\narrangement consisting of two identical mercury thermometers, one of which has a damp muslin wick covering the bulb. These\nare normally housed in a protective marine screen on each bridge wing. The dewpoint temperature may then be determined by\na “Dewpoint Table” to compare the wet and dry bulb temperatures. This figure is important when considering cargo ventilation\nrequirements.\nWhen using traditional wet and dry bulb thermometers, the accuracy of the dew point temperature will depend on the condition\nof the equipment. The muslin covering the wet bulb should be clean, the water in the reservoir should be distilled and the bulb\nitself should be wet. In order to ensure that the readings are correct, the device should always be positioned away from any\nexhaust vents, other draughts and all sources of heat. The readings should always be taken on the windward side of the vessel.\n(Cargo Ventilation and Precautions to Minimise Sweat, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":131,"source_page_end":131,"raw_source_text":"Are necessary instruments (with spare) to determine the dew point provided, maintained in good\ncondition and are there records of the calibration of such instruments? (V)\nGuide to Inspection\nDewpoint temperature may be measured by a variety of methods. Ships generally use a traditional wet and dry bulb\narrangement consisting of two identical mercury thermometers, one of which has a damp muslin wick covering the bulb. These\nare normally housed in a protective marine screen on each bridge wing. The dewpoint temperature may then be determined by\na “Dewpoint Table” to compare the wet and dry bulb temperatures. This figure is important when considering cargo ventilation\nrequirements.\nWhen using traditional wet and dry bulb thermometers, the accuracy of the dew point temperature will depend on the condition\nof the equipment. The muslin covering the wet bulb should be clean, the water in the reservoir should be distilled and the bulb\nitself should be wet. In order to ensure that the readings are correct, the device should always be positioned away from any\nexhaust vents, other draughts and all sources of heat. The readings should always be taken on the windward side of the vessel.\n(Cargo Ventilation and Precautions to Minimise Sweat, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.28","internal_question_no":"08B.028","question_sort_key":8202800.243,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":131,"source_page_end":131,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.29","internal_question_no":"08B.029","question_sort_key":8202900.244,"question_text":"Is ventilation of cargo holds, where required, being carried out and recorded?","guide_to_inspection":"The following should be recorded on each day for each hold:\n> All temperatures taken and dew points calculated\n> Whether or not ventilation carried out\n> Reason for not ventilating\n> Weather and sea condition\nVentilation rule applied (e.g., three –degree rule or dew point rule)\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":131,"source_page_end":131,"raw_source_text":"Is ventilation of cargo holds, where required, being carried out and recorded? (V)\nGuide to Inspection\nThe following should be recorded on each day for each hold:\n> All temperatures taken and dew points calculated\n> Whether or not ventilation carried out\n> Reason for not ventilating\n> Weather and sea condition\nVentilation rule applied (e.g., three –degree rule or dew point rule)\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.30","internal_question_no":"08B.030","question_sort_key":8203000.245,"question_text":"Is there evidence of a satisfactory grain stability calculation for the last voyage?","guide_to_inspection":"The inspector shall verify that the following has been considered during a grain loading calculation:\n> Using the stowage factor provided (and any ship’s experience factor is appropriate), and using the full hold volumes with\ntrimmed ends, determine the weight of cargo to be stowed in each full hold, and then determine the weight of cargo to be\nstowed in each slack hold, if applicable.\n> Determine the ullage or sounding of each slack hold\n> Using the volumetric heeling moment data, determine the volumetric heeling moment for each hold, assuming each full\nhold has untrimmed ends and using the ullage or sounding for each slack hold\n> Apply the stowage factor to the volumetric heeling moment and obtain the total grain heeling moment\n> Complete stability calculations to determine the ship’s fluid GM, the displacement and draft, and then determine from the\ndata the maximum permissible grain heeling moment for the ship’s loaded condition\n> Ensure the total grain heeling moment at each stage of the voyage is less than the corresponding maximum permissible\ngrain heeling moment, sometimes referred to as the maximum allowable grain heeling moment\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nAppropriate grain stability calculations, as required by the International Grain Code, should be carried out prior to loading grain.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":131,"source_page_end":131,"raw_source_text":"Is there evidence of a satisfactory grain stability calculation for the last voyage? (M)\nGuide to Inspection\nThe inspector shall verify that the following has been considered during a grain loading calculation:\n> Using the stowage factor provided (and any ship’s experience factor is appropriate), and using the full hold volumes with\ntrimmed ends, determine the weight of cargo to be stowed in each full hold, and then determine the weight of cargo to be\nstowed in each slack hold, if applicable.\n> Determine the ullage or sounding of each slack hold\n> Using the volumetric heeling moment data, determine the volumetric heeling moment for each hold, assuming each full\nhold has untrimmed ends and using the ullage or sounding for each slack hold\n> Apply the stowage factor to the volumetric heeling moment and obtain the total grain heeling moment\n> Complete stability calculations to determine the ship’s fluid GM, the displacement and draft, and then determine from the\ndata the maximum permissible grain heeling moment for the ship’s loaded condition\n> Ensure the total grain heeling moment at each stage of the voyage is less than the corresponding maximum permissible\ngrain heeling moment, sometimes referred to as the maximum allowable grain heeling moment\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nAppropriate grain stability calculations, as required by the International Grain Code, should be carried out prior to loading grain.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.31","internal_question_no":"08B.031","question_sort_key":8203100.246,"question_text":"Has a cargo loading/unloading plan providing detailed sequences of cargo and ballast transfer been prepared, understood, and signed off by the Master and deck officers?","guide_to_inspection":"General requirements:\nA cargo loading/unloading plan should be laid out in such a way that for each step of the cargo operation there is a clear\nindication of:\n> The quantity of cargo and the corresponding hold number(s) to be loaded/unloaded.\n> The amount of water ballast and the corresponding tank/hold number(s) to be discharged/loaded.\n> The ship’s draughts and trim at the completion of each step in the cargo operation.\n> The calculated value of the still-water shear forces and bending moments at the completion of each step in the cargo\noperation.\n> Estimated time for completion of each step in the cargo operation.\n> Assumed rate(s) of loading and unloading equipment.\n> Assumed ballasting rate(s)\nThe loading/unloading plan should indicate any allowances for cargo stoppage (which may be necessary to allow the ship to\nde-ballast when the loading rate is high), shifting ship, bunkering, draught checks, and cargo trimming. (Bulk Cargo Loading and\nDischarging Guidance, 2012) (Bulk Cargo Loading and Discharging Guidance, 2012)\nLoading plan consideration:\n> The arrangements at the port, including the number of loaders and their range of movement, the least depth alongside and\nthe air draft requirements.\n> The loading sequence, including the number of pours per hold, where loading should begin and where the final trimming\npours should be loaded.\n> De-ballasting, including the timing of that operation to coincide with the loading sequence and the need for a substantial\ntrim during stripping of the ballast tanks.\n> The shear force and bending moments and stability of the ship at all stages of the operation.\n> Trimming pours and the final draft requirements.\nUnloading plan consideration:\n> The port arrangements, including the number of unloaders available and their range of movement, the maximum draft\navailable and the minimum draft available.\n> The weight of cargo to be unloaded at the port or ports and its distribution on board.\n> Ballasting, including the timing of that ballasting operation, which should coincide with the unloading sequence and trim of\nthe ship.\n> The shear forces, bending moments and stability of the ship at all stages of the operation.\n> Final draft requirements and air draft requirements.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe cargo loading/unloading plan should be completed by the responsible officer prior to arrival at port and commencement of\ncargo operations and verified and approved by the Master.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":132,"source_page_end":132,"raw_source_text":"Has a cargo loading/unloading plan providing detailed sequences of cargo and ballast transfer been\nprepared, understood, and signed off by the Master and deck officers? (V)\nGuide to Inspection\nGeneral requirements:\nA cargo loading/unloading plan should be laid out in such a way that for each step of the cargo operation there is a clear\nindication of:\n> The quantity of cargo and the corresponding hold number(s) to be loaded/unloaded.\n> The amount of water ballast and the corresponding tank/hold number(s) to be discharged/loaded.\n> The ship’s draughts and trim at the completion of each step in the cargo operation.\n> The calculated value of the still-water shear forces and bending moments at the completion of each step in the cargo\noperation.\n> Estimated time for completion of each step in the cargo operation.\n> Assumed rate(s) of loading and unloading equipment.\n> Assumed ballasting rate(s)\nThe loading/unloading plan should indicate any allowances for cargo stoppage (which may be necessary to allow the ship to\nde-ballast when the loading rate is high), shifting ship, bunkering, draught checks, and cargo trimming. (Bulk Cargo Loading and\nDischarging Guidance, 2012) (Bulk Cargo Loading and Discharging Guidance, 2012)\nLoading plan consideration:\n> The arrangements at the port, including the number of loaders and their range of movement, the least depth alongside and\nthe air draft requirements.\n> The loading sequence, including the number of pours per hold, where loading should begin and where the final trimming\npours should be loaded.\n> De-ballasting, including the timing of that operation to coincide with the loading sequence and the need for a substantial\ntrim during stripping of the ballast tanks.\n> The shear force and bending moments and stability of the ship at all stages of the operation.\n> Trimming pours and the final draft requirements.\nUnloading plan consideration:\n> The port arrangements, including the number of unloaders available and their range of movement, the maximum draft\navailable and the minimum draft available.\n> The weight of cargo to be unloaded at the port or ports and its distribution on board.\n> Ballasting, including the timing of that ballasting operation, which should coincide with the unloading sequence and trim of\nthe ship.\n> The shear forces, bending moments and stability of the ship at all stages of the operation.\n> Final draft requirements and air draft requirements.\n(Bulk Cargoes: A Guide to Good Practice, 2016)\nThe cargo loading/unloading plan should be completed by the responsible officer prior to arrival at port and commencement of\ncargo operations and verified and approved by the Master.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.32","internal_question_no":"08B.032","question_sort_key":8203200.247,"question_text":"Are the hold bilges cleaned prior to loading and have all hold openings been made grain tight?","guide_to_inspection":"Hold bilges must be cleaned thoroughly to remove all residue, rust particles, and cargo stains etc. The filter (Rose Box) must be\ncleaned thoroughly. The bilge well sections shall be washed with continuous running of sea water to remove all odor and later\nrinsed with fresh water. The bilge well must be sponged dry to remove all trace of water and dried.\nAll tank-top and fuel tank sheathing must be grain tight. Where the condition of the sheathing renders this impracticable, the\nsheathing must be covered with hessian, polyethylene, paper, or other suitable material to prevent the ingress of grain.\nBilge spaces and bilge wells must be covered with hessian or similar porous material after inspection, in such a manner as to\nprevent the entry of grain into the bilge space or well, but to permit the entry of water.\nTween deck and other scuppers must be covered with hessian or similar porous material in such a manner as to prevent the\nentry of grain into the scupper opening but to permit the entry of drainage water.\n(Bulk Cargoes Hold Preparation and Cleaning, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":132,"source_page_end":132,"raw_source_text":"Are the hold bilges cleaned prior to loading and have all hold openings been made grain tight? (V)\nGuide to Inspection\nHold bilges must be cleaned thoroughly to remove all residue, rust particles, and cargo stains etc. The filter (Rose Box) must be\ncleaned thoroughly. The bilge well sections shall be washed with continuous running of sea water to remove all odor and later\nrinsed with fresh water. The bilge well must be sponged dry to remove all trace of water and dried.\nAll tank-top and fuel tank sheathing must be grain tight. Where the condition of the sheathing renders this impracticable, the\nsheathing must be covered with hessian, polyethylene, paper, or other suitable material to prevent the ingress of grain.\nBilge spaces and bilge wells must be covered with hessian or similar porous material after inspection, in such a manner as to\nprevent the entry of grain into the bilge space or well, but to permit the entry of water.\nTween deck and other scuppers must be covered with hessian or similar porous material in such a manner as to prevent the\nentry of grain into the scupper opening but to permit the entry of drainage water.\n(Bulk Cargoes Hold Preparation and Cleaning, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.33","internal_question_no":"08B.033","question_sort_key":8203300.248,"question_text":"Do records on board verify that cargo lights in holds, where fitted, were properly isolated before cargo was loaded?","guide_to_inspection":"Many bulk carrier/general cargo holds have fixed cargo lights. These can easily ignite combustible cargoes such as grain,\nanimal feed, wood chips, pulp, and paper if they are too close to the light. Cargo lights in holds need to be properly isolated before\ncargo is loaded. This is best done by removing fuses or other physical links in the electrical circuits so that the lights cannot be\nswitched on by mistake.\n(Fire! A Guide to the causes and prevention of cargo fire, 2017)\nThere are certain types of cargo hold lights that can be considered safe for continuous use without posing a risk to the cargo.\nExamples include:\nLED Lights\n> Low heat emission\n> Energy-efficient and long-lasting\nFluorescent Lights\n> Generally safe for use around combustible cargo\n> Commonly used in car carriers\n> Low risk of ignition due to lower operating temperatures.\nIf such lights are installed inside the cargo hold, and there is objective evidence of regular maintenance in accordance with the\nmanufacturer’s recommendations, along with procedures in the SMS that address the requirement for isolating these lights\nbased on the type of cargo, and these procedures have been followed, then the inspector should select “Yes” as the answer to\nthis question.\nThe inspector should also record in the comments section the measures in place to ensure the safety of the cargo within the\nhold.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":133,"source_page_end":133,"raw_source_text":"Do records on board verify that cargo lights in holds, where fitted, were properly isolated before cargo\nwas loaded? (V)\nGuide to Inspection\nMany bulk carrier/general cargo holds have fixed cargo lights. These can easily ignite combustible cargoes such as grain,\nanimal feed, wood chips, pulp, and paper if they are too close to the light. Cargo lights in holds need to be properly isolated before\ncargo is loaded. This is best done by removing fuses or other physical links in the electrical circuits so that the lights cannot be\nswitched on by mistake.\n(Fire! A Guide to the causes and prevention of cargo fire, 2017)\nThere are certain types of cargo hold lights that can be considered safe for continuous use without posing a risk to the cargo.\nExamples include:\nLED Lights\n> Low heat emission\n> Energy-efficient and long-lasting\nFluorescent Lights\n> Generally safe for use around combustible cargo\n> Commonly used in car carriers\n> Low risk of ignition due to lower operating temperatures.\nIf such lights are installed inside the cargo hold, and there is objective evidence of regular maintenance in accordance with the\nmanufacturer’s recommendations, along with procedures in the SMS that address the requirement for isolating these lights\nbased on the type of cargo, and these procedures have been followed, then the inspector should select “Yes” as the answer to\nthis question.\nThe inspector should also record in the comments section the measures in place to ensure the safety of the cargo within the\nhold.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.34","internal_question_no":"08B.034","question_sort_key":8203400.249,"question_text":"Is an adequate record of all cargo operation activities maintained during loading and unloading?","guide_to_inspection":"The following should be recorded in the port logbook or deck logbook:\n> Starting and stopping of work at each hold, times, and dates\n> Tonnages loaded per pour into each hold, and a running total loaded; and in the case of unloading, tonnages offloaded per\nshift from each hold and a running total offloaded.\n> Weather conditions at intervals – for example 6 hours.\n> Use of ship’s cranes, if appropriate\n> Movement of shore cranes, loaders, or floating crane alongside\n> Movement of barges alongside and of floating cranes or loaders if ship is at anchor\n> Opening and closing of hatches\n> Period of precipitation\n> Draft readings\n> Any delays caused on board\n> Any delays caused ashore\n> Any surveyors attending or boarding with reason for attendance\n> Any stevedore’s damage to ship’s structure and/or fittings\n> Cargo temperature in particular for grain, seed cake and coal\n(Bulk Cargoes: A Guide to Good Practice, 2016)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":133,"source_page_end":133,"raw_source_text":"Is an adequate record of all cargo operation activities maintained during loading and unloading? (V)\nGuide to Inspection\nThe following should be recorded in the port logbook or deck logbook:\n> Starting and stopping of work at each hold, times, and dates\n> Tonnages loaded per pour into each hold, and a running total loaded; and in the case of unloading, tonnages offloaded per\nshift from each hold and a running total offloaded.\n> Weather conditions at intervals – for example 6 hours.\n> Use of ship’s cranes, if appropriate\n> Movement of shore cranes, loaders, or floating crane alongside\n> Movement of barges alongside and of floating cranes or loaders if ship is at anchor\n> Opening and closing of hatches\n> Period of precipitation\n> Draft readings\n> Any delays caused on board\n> Any delays caused ashore\n> Any surveyors attending or boarding with reason for attendance\n> Any stevedore’s damage to ship’s structure and/or fittings\n> Cargo temperature in particular for grain, seed cake and coal\n(Bulk Cargoes: A Guide to Good Practice, 2016)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08B","section_number":8,"section_letter":"B","section_title":"Cargo Operation - Bulk Grain","printed_question_no":"8.35","internal_question_no":"08B.035","question_sort_key":8203500.25,"question_text":"Are the dangers associated with oxygen depletion of grain cargo understood by officers and crew, and have reasonable precautions been taken during routine inspections of the cargo, when entering the holds and adjacent spaces?","guide_to_inspection":"Most grain cargoes may deplete the oxygen levels in cargo holds and possibly in adjacent spaces. All cargo holds and adjacent\nspaces must be treated as enclosed spaces and subject to controlled entry. (Carriage of Bulk Grain Cargoes, 2015)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":133,"source_page_end":133,"raw_source_text":"Are the dangers associated with oxygen depletion of grain cargo understood by officers and crew,\nand have reasonable precautions been taken during routine inspections of the cargo, when entering\nthe holds and adjacent spaces? (V)\nGuide to Inspection\nMost grain cargoes may deplete the oxygen levels in cargo holds and possibly in adjacent spaces. All cargo holds and adjacent\nspaces must be treated as enclosed spaces and subject to controlled entry. (Carriage of Bulk Grain Cargoes, 2015)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.1","internal_question_no":"08C.001","question_sort_key":8300100.251,"question_text":"This question has been removed from the current version of the document.","guide_to_inspection":"","answer_type":"removed","answer_options":[],"answer_options_inferred":false,"inspection_marker":"","is_removed_question":true,"is_active":false,"guide_status":"removed","source_page_start":134,"source_page_end":134,"raw_source_text":"This question has been removed from the current version of the document.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.2","internal_question_no":"08C.002","question_sort_key":8300200.252,"question_text":"Has appropriate cargo information been provided to the vessel prior to loading?","guide_to_inspection":"The shipper shall provide the Master or his representative with appropriate information on the cargo sufficiently in advance of\nloading, to enable the precautions which may be necessary for proper stowage and safe carriage of the cargo to be put into\neffect. Such information shall be confirmed in writing and by appropriate shipping documents prior to loading the cargo on the\nship.\nIn the case of general cargo, and of cargo carried in cargo units, a general description of the cargo, the gross mass of the\ncargo or of the cargo units, and any relevant special properties of the cargo units. For the purpose of this regulation, the\ncargo information required in sub-chapter 1.9 of the Code of Safe Practice for Cargo Stowage and Securing, adopted by the\nOrganisation by resolution A.714 (17), as may be amended, shall be provided.\nPrior to loading cargo units on board ships, the shipper shall ensure that the gross mass of such units is in accordance with the\ngross mass declared on the shipping documents. (SOLAS 74,2020)\nPrior to shipment the shipper should provide all necessary information about the cargo to enable the shipowner or ship operator\nto ensure that:\n> The different commodities to be carried are compatible with each other or suitably separated\n> The cargo is suitable for the ship\n> The ship is suitable for the cargo, and\n> The cargo can be safely stowed and secured on board the ship and transported under all expected conditions during the\nintended voyage.\nThe Master should be provided with adequate information regarding the cargo to be carried so that its stowage may be properly\nplanned for handling and transport.\n(CSS code, 2011)\nIf the vessel is loading heavy lift cargo, the shipper should provide the following information to the Master:\n> A general description of the cargo\n> The gross mass of the item or of each item if there are more than one\n> The principle dimensions of the item or items and, if possible, scale drawings\n> The location of the centre of gravity of each item\n> Particulars of the bedding area of the cargo units and details of any precautions with regard to the bedding of the item(s)\n> Details of lifting points or slinging positions and, if possible, information on how best to lift each item\n> Details of securing points, including their strength and radius of strength.\n(Bliault and North of England P & I Association, 2007)\n> The following information as applicable for each parcel of timber cargo should be provided by the shipper and collected by\nthe Master or his representative:\n> Total amount of cargo intended as deck cargo\n> Typical dimensions of the cargo\n> Number of bundles\n> Density of the cargo\n> Stowage factor of the cargo\n> Racking strength for packaged cargo\n> Type of cover of packages and whether non-slip type, and\n> Relevant coefficients of friction, including covers of sawn wooden packages if applicable.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":134,"source_page_end":135,"raw_source_text":"Has appropriate cargo information been provided to the vessel prior to loading? (V)\nGuide to Inspection\nThe shipper shall provide the Master or his representative with appropriate information on the cargo sufficiently in advance of\nloading, to enable the precautions which may be necessary for proper stowage and safe carriage of the cargo to be put into\neffect. Such information shall be confirmed in writing and by appropriate shipping documents prior to loading the cargo on the\nship.\nIn the case of general cargo, and of cargo carried in cargo units, a general description of the cargo, the gross mass of the\ncargo or of the cargo units, and any relevant special properties of the cargo units. For the purpose of this regulation, the\ncargo information required in sub-chapter 1.9 of the Code of Safe Practice for Cargo Stowage and Securing, adopted by the\nOrganisation by resolution A.714 (17), as may be amended, shall be provided.\nPrior to loading cargo units on board ships, the shipper shall ensure that the gross mass of such units is in accordance with the\ngross mass declared on the shipping documents. (SOLAS 74,2020)\nPrior to shipment the shipper should provide all necessary information about the cargo to enable the shipowner or ship operator\nto ensure that:\n> The different commodities to be carried are compatible with each other or suitably separated\n> The cargo is suitable for the ship\n> The ship is suitable for the cargo, and\n> The cargo can be safely stowed and secured on board the ship and transported under all expected conditions during the\nintended voyage.\nThe Master should be provided with adequate information regarding the cargo to be carried so that its stowage may be properly\nplanned for handling and transport.\n(CSS code, 2011)\nIf the vessel is loading heavy lift cargo, the shipper should provide the following information to the Master:\n> A general description of the cargo\n> The gross mass of the item or of each item if there are more than one\n> The principle dimensions of the item or items and, if possible, scale drawings\n> The location of the centre of gravity of each item\n> Particulars of the bedding area of the cargo units and details of any precautions with regard to the bedding of the item(s)\n> Details of lifting points or slinging positions and, if possible, information on how best to lift each item\n> Details of securing points, including their strength and radius of strength.\n(Bliault and North of England P & I Association, 2007)\n> The following information as applicable for each parcel of timber cargo should be provided by the shipper and collected by\nthe Master or his representative:\n> Total amount of cargo intended as deck cargo\n> Typical dimensions of the cargo\n> Number of bundles\n> Density of the cargo\n> Stowage factor of the cargo\n> Racking strength for packaged cargo\n> Type of cover of packages and whether non-slip type, and\n> Relevant coefficients of friction, including covers of sawn wooden packages if applicable.\n(Code of Safe Practice for Ships Carrying Timber Deck Cargoes, 2012)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.3","internal_question_no":"08C.003","question_sort_key":8300300.253,"question_text":"If dangerous goods are carried in packaged form, have appropriate documents been provided to the vessels?","guide_to_inspection":"The dangerous goods transport document shall include a certification or declaration that the consignment is acceptable for\ntransport and that the goods are properly packaged, marked, and labelled, and in proper condition for transport in accordance\nwith the applicable regulations.\n(IMDG Code, 2020)\nWhen dangerous goods are packed or loaded into any container or vehicle, those responsible for packing the container or\nvehicle shall provide a “container/vehicle packing certificate” specifying the container/vehicle identification number(s) and\ncertifying that the operation has been carried out in accordance with the following conditions:\n> The container/vehicle was clean, dry and apparently fit to receive the goods.\n> Packages which need to be segregated in accordance with applicable segregation requirements have not been packed\ntogether onto or in the container/vehicle (unless approved by the competent authority concerned, in accordance with\n7.3.4.1);\n> All packages have been externally inspected for damage, and only sound packages have been loaded.\n> Drums have been stowed in an upright position, unless otherwise authorised by the competent authority, and all goods\nhave been properly loaded and, where necessary, adequately braced with securing material to suit the mode(s) of transport\nfor the intended journey.\n> Goods loaded in bulk have been evenly distributed within the container/vehicle.\n> For consignments including goods of class 1 other than division 1.4, the container/vehicle is structurally serviceable in\naccordance with 7.1.2.\n> The container/vehicle and packages are properly marked, labelled, and placarded, as appropriate; .8 When substances\npresenting a risk of asphyxiation are used for cooling or conditioning purposes (such as dry ice (UN 1845) or nitrogen,\nrefrigerated liquid (UN 1977) or argon, refrigerated liquid (UN 1951)), the container/vehicle is externally marked in\naccordance with 5.5.3.6; and\n> A dangerous goods transport document, as indicated in 5.4.1, has been received for each dangerous goods consignment\nloaded in the container/vehicle. Note: The container/vehicle packing certificate is not required for portable tanks.\n(IMDG Code, 2020)\nEach ship carrying dangerous goods in packaged form shall have a special list or manifest setting forth, in accordance with the\nclassification set out in the IMDG Code, the dangerous goods on board and the location.\nA detailed stowage plan, which identifies by class and sets out the location of all dangerous goods on board, may be used\nin place of such a special list or manifest. A copy of one of these documents shall be made available before departure to the\nperson or organisation designated by the port state authority.\n(SOLAS 74, 2020)\nThe AMSA Information Sheet reminds ship managers about the requirements for the safe carriage of Ammonium Nitrate on\nboard ships, with particular emphasis on:\nStowage under deck in a clean cargo space capable of being opened up in an emergency.\nProtection from sources of heat.\nStowage out of direct contact with metal engine room bulkheads.\nCarriage of Ammonium Nitrate in Flexible Intermediate Bulk Containers (FIBC).\nThe full document can be accessed by clicking here.\nThe atmosphere in any space containing dangerous goods may pose serious risks to the health or life of anyone entering.\nHazards can include flammable, toxic, corrosive, or asphyxiant gases or vapors, residues on packages, and spilled materials.\nThese same dangers may also exist in spaces adjacent to or connected with the cargo spaces.\nInformation on the hazards of specific substances can be found in the IMDG Code, the Safety Data Sheet (SDS), and the\nShipper’s Declaration. If there is evidence or suspicion of leakage of dangerous substances, the precautions specified in\nMSC.581(110) (2025) should be followed.\nPersonnel tasked with handling spillages or removing defective or damaged packages should be properly trained and equipped\nwith suitable breathing apparatus and protective clothing appropriate for the task.","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":135,"source_page_end":136,"raw_source_text":"If dangerous goods are carried in packaged form, have appropriate documents been provided to\nthe vessels? (V)\nGuide to Inspection\nThe dangerous goods transport document shall include a certification or declaration that the consignment is acceptable for\ntransport and that the goods are properly packaged, marked, and labelled, and in proper condition for transport in accordance\nwith the applicable regulations.\n(IMDG Code, 2020)\nWhen dangerous goods are packed or loaded into any container or vehicle, those responsible for packing the container or\nvehicle shall provide a “container/vehicle packing certificate” specifying the container/vehicle identification number(s) and\ncertifying that the operation has been carried out in accordance with the following conditions:\n> The container/vehicle was clean, dry and apparently fit to receive the goods.\n> Packages which need to be segregated in accordance with applicable segregation requirements have not been packed\ntogether onto or in the container/vehicle (unless approved by the competent authority concerned, in accordance with\n7.3.4.1);\n> All packages have been externally inspected for damage, and only sound packages have been loaded.\n> Drums have been stowed in an upright position, unless otherwise authorised by the competent authority, and all goods\nhave been properly loaded and, where necessary, adequately braced with securing material to suit the mode(s) of transport\nfor the intended journey.\n> Goods loaded in bulk have been evenly distributed within the container/vehicle.\n> For consignments including goods of class 1 other than division 1.4, the container/vehicle is structurally serviceable in\naccordance with 7.1.2.\n> The container/vehicle and packages are properly marked, labelled, and placarded, as appropriate; .8 When substances\npresenting a risk of asphyxiation are used for cooling or conditioning purposes (such as dry ice (UN 1845) or nitrogen,\nrefrigerated liquid (UN 1977) or argon, refrigerated liquid (UN 1951)), the container/vehicle is externally marked in\naccordance with 5.5.3.6; and\n> A dangerous goods transport document, as indicated in 5.4.1, has been received for each dangerous goods consignment\nloaded in the container/vehicle. Note: The container/vehicle packing certificate is not required for portable tanks.\n(IMDG Code, 2020)\nEach ship carrying dangerous goods in packaged form shall have a special list or manifest setting forth, in accordance with the\nclassification set out in the IMDG Code, the dangerous goods on board and the location.\nA detailed stowage plan, which identifies by class and sets out the location of all dangerous goods on board, may be used\nin place of such a special list or manifest. A copy of one of these documents shall be made available before departure to the\nperson or organisation designated by the port state authority.\n(SOLAS 74, 2020)\nThe AMSA Information Sheet reminds ship managers about the requirements for the safe carriage of Ammonium Nitrate on\nboard ships, with particular emphasis on:\nStowage under deck in a clean cargo space capable of being opened up in an emergency.\nProtection from sources of heat.\nStowage out of direct contact with metal engine room bulkheads.\nCarriage of Ammonium Nitrate in Flexible Intermediate Bulk Containers (FIBC).\nThe full document can be accessed by clicking here.\nThe atmosphere in any space containing dangerous goods may pose serious risks to the health or life of anyone entering.\nHazards can include flammable, toxic, corrosive, or asphyxiant gases or vapors, residues on packages, and spilled materials.\nThese same dangers may also exist in spaces adjacent to or connected with the cargo spaces.\nInformation on the hazards of specific substances can be found in the IMDG Code, the Safety Data Sheet (SDS), and the\nShipper’s Declaration. If there is evidence or suspicion of leakage of dangerous substances, the precautions specified in\nMSC.581(110) (2025) should be followed.\nPersonnel tasked with handling spillages or removing defective or damaged packages should be properly trained and equipped\nwith suitable breathing apparatus and protective clothing appropriate for the task.","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.4","internal_question_no":"08C.004","question_sort_key":8300400.254,"question_text":"Are procedures for safe lashing and securing operations incorporated in the ship’s SMS?","guide_to_inspection":"Procedures for safe lashing and securing operations should be included in the ship’s Safety Management System as part of the\nISM Code documentation.\n(CSS code, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"M","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":136,"source_page_end":136,"raw_source_text":"Are procedures for safe lashing and securing operations incorporated in the ship’s SMS? (M)\nGuide to Inspection\nProcedures for safe lashing and securing operations should be included in the ship’s Safety Management System as part of the\nISM Code documentation.\n(CSS code, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}},{"section_code":"08C","section_number":8,"section_letter":"C","section_title":"Cargo operation - general cargo","printed_question_no":"8.5","internal_question_no":"08C.005","question_sort_key":8300500.255,"question_text":"Is an approved ship-specific Cargo Securing Manual available and are officers thoroughly familiar with the contents of the manual?","guide_to_inspection":"In accordance with the SOLAS chapters VI, VII and the Code of Safe Practice for Cargo Stowage and Securing (CSS Code), cargo\nunits, including containers shall be stowed and secured throughout the voyage in accordance with a Cargo Securing Manual\n(CSM), approved by the Administration.\nThe CSM should be developed, taking into account the recommendations given in these Guidelines, and should be written in the\nworking language or languages of the ship. If the language or languages used is not English, French or Spanish, a translation\ninto one of these languages should be included.\n> The guidance given in the CSM should by no means rule out the principles of good seamanship, neither can it replace\nexperience in stowage and securing practice.\n> The information and requirements set forth in the manual are consistent with the requirements of the vessel’s trim and\nstability booklet, International Load Line Certificate (1966), the hull strength loading manual (if provided) and with the\nrequirements of the International Maritime Dangerous Goods (IMDG) Code (if applicable).\n> The CSM specifies arrangements and cargo-securing devices provided on board the ship for the correct application to and\nthe securing of cargo units, containers, vehicles and other entities, based on transverse, longitudinal and vertical forces\nwhich may arise during adverse weather and sea conditions.\n> It is imperative to the safety of the ship and the protection of the cargo and personnel that the securing of the cargo is\ncarried out properly and that only appropriate securing points or fittings should be used for securing cargo.\n> The cargo-securing devices mentioned in this manual should be applied so as to be suitable and adapted to the quantity,\ntype of packaging, and physical properties of the cargo to be carried. When new or alternative types of cargo-securing\ndevices are introduced, the manual should be revised accordingly. Alternative cargo- securing devices introduced should\nnot have less strength than the devices being replaced.\n> There should be a sufficient quantity of reserve cargo-securing devices on board the ship.\n> Information on the strength and instructions for the use and maintenance of each specific type of cargo-securing device,\nwhere applicable, is provided in this manual. The cargo- securing devices should be maintained in a satisfactory condition.\nItems worn or damaged to such an extent that their quality is impaired should be replaced.\n> The Cargo Safe Access Plan (CSAP) is intended to provide detailed information for persons engaged in work connected\nwith cargo stowage and securing. Safe access should be provided and maintained in accordance with this plan.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)\nNote: The Cargo Safe Access Plan (CSAP) is only required for containerships with keel-laying date on or after 1 January 2015.\nThe Cargo Securing Manual should be updated as appropriate. Whenever the ship’s outfit of portable cargo securing devices\nchanges, those changes should be recorded in the appropriate section of the CSM. An appropriate record should be completed\nwhenever routine visual examinations or periodic detailed examinations and re-testing of the devices are carried out.\n(Bliault and North of England, P & I Association, 2007)\nLashing plans contained within the approved Cargo Securing Manual should be compatible with the current design of the ship\nand the intended container securing method is both safe and physically possible. The CSM, lashing plans and the CSAP are kept\nup to date.\nLashing plans and the CSAP are compatible with the design of the vessel and the equipment available.\n(CSS code, 2011)","answer_type":"yes_no_na_nv","answer_options":["YES","NO","N/A","N/V"],"answer_options_inferred":false,"inspection_marker":"V","is_removed_question":false,"is_active":true,"guide_status":"provided","source_page_start":136,"source_page_end":136,"raw_source_text":"Is an approved ship-specific Cargo Securing Manual available and are officers thoroughly familiar\nwith the contents of the manual? (V)\nGuide to Inspection\nIn accordance with the SOLAS chapters VI, VII and the Code of Safe Practice for Cargo Stowage and Securing (CSS Code), cargo\nunits, including containers shall be stowed and secured throughout the voyage in accordance with a Cargo Securing Manual\n(CSM), approved by the Administration.\nThe CSM should be developed, taking into account the recommendations given in these Guidelines, and should be written in the\nworking language or languages of the ship. If the language or languages used is not English, French or Spanish, a translation\ninto one of these languages should be included.\n> The guidance given in the CSM should by no means rule out the principles of good seamanship, neither can it replace\nexperience in stowage and securing practice.\n> The information and requirements set forth in the manual are consistent with the requirements of the vessel’s trim and\nstability booklet, International Load Line Certificate (1966), the hull strength loading manual (if provided) and with the\nrequirements of the International Maritime Dangerous Goods (IMDG) Code (if applicable).\n> The CSM specifies arrangements and cargo-securing devices provided on board the ship for the correct application to and\nthe securing of cargo units, containers, vehicles and other entities, based on transverse, longitudinal and vertical forces\nwhich may arise during adverse weather and sea conditions.\n> It is imperative to the safety of the ship and the protection of the cargo and personnel that the securing of the cargo is\ncarried out properly and that only appropriate securing points or fittings should be used for securing cargo.\n> The cargo-securing devices mentioned in this manual should be applied so as to be suitable and adapted to the quantity,\ntype of packaging, and physical properties of the cargo to be carried. When new or alternative types of cargo-securing\ndevices are introduced, the manual should be revised accordingly. Alternative cargo- securing devices introduced should\nnot have less strength than the devices being replaced.\n> There should be a sufficient quantity of reserve cargo-securing devices on board the ship.\n> Information on the strength and instructions for the use and maintenance of each specific type of cargo-securing device,\nwhere applicable, is provided in this manual. The cargo- securing devices should be maintained in a satisfactory condition.\nItems worn or damaged to such an extent that their quality is impaired should be replaced.\n> The Cargo Safe Access Plan (CSAP) is intended to provide detailed information for persons engaged in work connected\nwith cargo stowage and securing. Safe access should be provided and maintained in accordance with this plan.\n(MSC.1/Circ.1353/Rev.1, Revised Guidelines for the Preparation of the Cargo Securing Manual, 2014)\nNote: The Cargo Safe Access Plan (CSAP) is only required for containerships with keel-laying date on or after 1 January 2015.\nThe Cargo Securing Manual should be updated as appropriate. Whenever the ship’s outfit of portable cargo securing devices\nchanges, those changes should be recorded in the appropriate section of the CSM. An appropriate record should be completed\nwhenever routine visual examinations or periodic detailed examinations and re-testing of the devices are carried out.\n(Bliault and North of England, P & I Association, 2007)\nLashing plans contained within the approved Cargo Securing Manual should be compatible with the current design of the ship\nand the intended container securing method is both safe and physically possible. The CSM, lashing plans and the CSAP are kept\nup to date.\nLashing plans and the CSAP are compatible with the design of the vessel and the equipment available.\n(CSS code, 2011)","metadata":{"question_set_code":"RISQ_3_2","provider":"RightShip","extracted_from_preview":true}}]}$RISQQ81$::jsonb AS payload
),
qs AS (
  SELECT id AS question_set_id FROM public.risq_question_sets WHERE question_set_code = 'RISQ_3_2' LIMIT 1
),
input_rows AS (
  SELECT *
  FROM payload p
  CROSS JOIN LATERAL jsonb_to_recordset(p.payload->'questions') AS r(
    section_code text,
    section_number integer,
    section_letter text,
    section_title text,
    printed_question_no text,
    internal_question_no text,
    question_sort_key numeric,
    question_text text,
    guide_to_inspection text,
    answer_type text,
    answer_options jsonb,
    answer_options_inferred boolean,
    inspection_marker text,
    is_removed_question boolean,
    is_active boolean,
    guide_status text,
    source_page_start integer,
    source_page_end integer,
    raw_source_text text,
    metadata jsonb
  )
),
section_lookup AS (
  SELECT s.id AS section_id, s.question_set_id, s.section_code
  FROM public.risq_sections s
  JOIN qs ON qs.question_set_id = s.question_set_id
)
INSERT INTO public.risq_questions (
  question_set_id,
  section_id,
  section_code,
  section_number,
  section_letter,
  section_title,
  printed_question_no,
  internal_question_no,
  question_sort_key,
  question_text,
  guide_to_inspection,
  answer_type,
  answer_options,
  answer_options_inferred,
  inspection_marker,
  is_removed_question,
  is_active,
  guide_status,
  source_page_start,
  source_page_end,
  raw_source_text,
  source_hash,
  metadata,
  created_by,
  updated_by
)
SELECT
  qs.question_set_id,
  sl.section_id,
  i.section_code,
  i.section_number,
  i.section_letter,
  i.section_title,
  i.printed_question_no,
  i.internal_question_no,
  i.question_sort_key,
  i.question_text,
  i.guide_to_inspection,
  i.answer_type,
  i.answer_options,
  COALESCE(i.answer_options_inferred, false),
  COALESCE(i.inspection_marker, ''),
  COALESCE(i.is_removed_question, false),
  COALESCE(i.is_active, true),
  i.guide_status,
  i.source_page_start,
  i.source_page_end,
  i.raw_source_text,
  md5(COALESCE(i.question_text, '') || '|' || COALESCE(i.guide_to_inspection, '') || '|' || COALESCE(i.raw_source_text, '')),
  COALESCE(i.metadata, '{}'::jsonb),
  auth.uid(),
  auth.uid()
FROM input_rows i
CROSS JOIN qs
JOIN section_lookup sl
  ON sl.question_set_id = qs.question_set_id
 AND sl.section_code = i.section_code
ON CONFLICT (question_set_id, internal_question_no)
DO UPDATE SET
  section_id = EXCLUDED.section_id,
  section_code = EXCLUDED.section_code,
  section_number = EXCLUDED.section_number,
  section_letter = EXCLUDED.section_letter,
  section_title = EXCLUDED.section_title,
  printed_question_no = EXCLUDED.printed_question_no,
  question_sort_key = EXCLUDED.question_sort_key,
  question_text = EXCLUDED.question_text,
  guide_to_inspection = EXCLUDED.guide_to_inspection,
  answer_type = EXCLUDED.answer_type,
  answer_options = EXCLUDED.answer_options,
  answer_options_inferred = EXCLUDED.answer_options_inferred,
  inspection_marker = EXCLUDED.inspection_marker,
  is_removed_question = EXCLUDED.is_removed_question,
  is_active = EXCLUDED.is_active,
  guide_status = EXCLUDED.guide_status,
  source_page_start = EXCLUDED.source_page_start,
  source_page_end = EXCLUDED.source_page_end,
  raw_source_text = EXCLUDED.raw_source_text,
  source_hash = EXCLUDED.source_hash,
  metadata = EXCLUDED.metadata,
  updated_by = auth.uid();

COMMIT;

SELECT
  'RISQ question chunk 8/15 imported.' AS result,
  '08B.007' AS chunk_first_question,
  '08C.005' AS chunk_last_question,
  (SELECT COUNT(*) FROM public.risq_questions q JOIN public.risq_question_sets qs ON qs.id = q.question_set_id WHERE qs.question_set_code = 'RISQ_3_2') AS total_questions_imported_so_far;
